import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Properly encoding user input to prevent XSS
        String safeUserInput = "";
        try {
            safeUserInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            // Handle encoding exception
            e.printStackTrace();
        }

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<head><title>XSS Secure Page</title></head>");
        out.println("<body>");
        out.println("<p>User Input: " + safeUserInput + "</p>");
        out.println("</body>");
        out.println("</html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
